+func TestTotpRFCVector(t *testing.T) {
+	key := []byte("12345678901234567890")
+	cases := []struct {
+		ts   int64
+		want string
+	}{
+		{59, "287082"},
+		{1111111109, "081804"},
+		{1111111111, "050471"},
+		{1234567890, "005924"},
+		{2000000000, "279037"},
+		{20000000000, "353130"},
+	}
+	for _, tc := range cases {
+		got := totp(key, time.Unix(tc.ts, 0))
+		if got != tc.want {
+			t.Fatalf("totp(%d)=%s want %s", tc.ts, got, tc.want)
+		}
+	}
+}
